1	export type Cell = [number, number];
2	
3	const cellKey = (x: number, y: number): string => `${x},${y}`;
4	
5	const parseCellKey = (key: string): Cell => {
6	  const [xStr, yStr] = key.split(",");
7	  return [Number(xStr), Number(yStr)];
8	};
9	
10	export function nextGeneration(cells: Cell[]): Cell[] {
11	  const liveSet = new Set<string>(cells.map(([x, y]) => cellKey(x, y)));
12	
13	  const neighborCounts = new Map<string, number>();
14	  for (const [x, y] of cells) {
15	    for (let dx = -1; dx <= 1; dx++) {
16	      for (let dy = -1; dy <= 1; dy++) {
17	        if (dx === 0 && dy === 0) continue;
18	        const key = cellKey(x + dx, y + dy);
19	        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
20	      }
21	    }
22	  }
23	
24	  const result: Cell[] = [];
25	  for (const [key, count] of neighborCounts) {
26	    const isAlive = liveSet.has(key);
27	    if ((isAlive && count === 2) || count === 3) {
28	      result.push(parseCellKey(key));
29	    }
30	  }
31	
32	  return result;
33	}
